#include <iostream>
using namespace std;

int main() {
    int number, sum = 0, digit;

    cin >> number;

    // Ensure the number is a 3-digit number
    if (number < 100 || number > 999) {
        cout << "Please enter a valid 3-digit number." << endl;
        //return 1; // Exit the program if the input is not a 3-digit number
    }

    else
    {
    // Extract individual digits and sum them
       while (number != 0) {
         digit = number % 10;  // Get the last digit
         sum += digit;          // Add the digit to the sum
         number /= 10;          // Remove the last digit from the number
        }
    cout << sum << endl;
    }    
    return 0;
}

